// SessionServiceHandler is an implementation of the session.v1.SessionService service.
type SessionServiceHandler interface {
	// ListSessions returns all sessions with optional filtering.
	ListSessions(context.Context, *connect.Request[v1.ListSessionsRequest]) (*connect.Response[v1.ListSessionsResponse], error)
	// GetSession retrieves a specific session by ID.
	GetSession(context.Context, *connect.Request[v1.GetSessionRequest]) (*connect.Response[v1.GetSessionResponse], error)
	// CreateSession initializes a new AI agent session with tmux and git worktree.
	CreateSession(context.Context, *connect.Request[v1.CreateSessionRequest]) (*connect.Response[v1.CreateSessionResponse], error)
	// UpdateSession modifies session properties (pause/resume, category, etc).
	UpdateSession(context.Context, *connect.Request[v1.UpdateSessionRequest]) (*connect.Response[v1.UpdateSessionResponse], error)
	// DeleteSession stops and removes a session, cleaning up resources.
	DeleteSession(context.Context, *connect.Request[v1.DeleteSessionRequest]) (*connect.Response[v1.DeleteSessionResponse], error)
	// WatchSessions streams real-time session events (created/updated/deleted).
	// Server-streaming RPC for live updates without polling.
	WatchSessions(context.Context, *connect.Request[v1.WatchSessionsRequest], *connect.ServerStream[v1.SessionEvent]) error
	// StreamTerminal provides bidirectional streaming for terminal I/O.
	// Clients can send input and receive output from the tmux PTY.
	StreamTerminal(context.Context, *connect.BidiStream[v1.TerminalData, v1.TerminalData]) error
	// GetSessionDiff retrieves the current git diff for a session.
	GetSessionDiff(context.Context, *connect.Request[v1.GetSessionDiffRequest]) (*connect.Response[v1.GetSessionDiffResponse], error)
	// GetVCSStatus retrieves the current version control status for a session.
	// Returns branch info, changed files, staged/unstaged status, and remote sync state.
	GetVCSStatus(context.Context, *connect.Request[v1.GetVCSStatusRequest]) (*connect.Response[v1.GetVCSStatusResponse], error)
	// GetReviewQueue returns sessions needing user attention with priority ordering.
	GetReviewQueue(context.Context, *connect.Request[v1.GetReviewQueueRequest]) (*connect.Response[v1.GetReviewQueueResponse], error)
	// AcknowledgeSession marks a session as acknowledged in the review queue.
	// The session won't reappear in the queue until it receives an update.
	AcknowledgeSession(context.Context, *connect.Request[v1.AcknowledgeSessionRequest]) (*connect.Response[v1.AcknowledgeSessionResponse], error)
	// GetLogs retrieves application logs with optional filtering and search.
	GetLogs(context.Context, *connect.Request[v1.GetLogsRequest]) (*connect.Response[v1.GetLogsResponse], error)
	// WatchReviewQueue streams real-time review queue events (items added/removed/updated).
	// Server-streaming RPC for live queue updates without polling.
	WatchReviewQueue(context.Context, *connect.Request[v1.WatchReviewQueueRequest], *connect.ServerStream[v1.ReviewQueueEvent]) error
	// LogUserInteraction logs a user interaction event for audit trail.
	// Records user actions for compliance, debugging, and analytics.
	LogUserInteraction(context.Context, *connect.Request[v1.LogUserInteractionRequest]) (*connect.Response[v1.LogUserInteractionResponse], error)
	// GetClaudeConfig retrieves a Claude configuration file by name (CLAUDE.md, settings.json, agents.md).
	GetClaudeConfig(context.Context, *connect.Request[v1.GetClaudeConfigRequest]) (*connect.Response[v1.GetClaudeConfigResponse], error)
	// ListClaudeConfigs returns all configuration files in the ~/.claude directory.
	ListClaudeConfigs(context.Context, *connect.Request[v1.ListClaudeConfigsRequest]) (*connect.Response[v1.ListClaudeConfigsResponse], error)
	// UpdateClaudeConfig updates a Claude configuration file with atomic write and backup.
	UpdateClaudeConfig(context.Context, *connect.Request[v1.UpdateClaudeConfigRequest]) (*connect.Response[v1.UpdateClaudeConfigResponse], error)
	// ListClaudeHistory returns Claude session history entries with optional filtering.
	ListClaudeHistory(context.Context, *connect.Request[v1.ListClaudeHistoryRequest]) (*connect.Response[v1.ListClaudeHistoryResponse], error)
	// GetClaudeHistoryDetail retrieves detailed information for a specific history entry.
	GetClaudeHistoryDetail(context.Context, *connect.Request[v1.GetClaudeHistoryDetailRequest]) (*connect.Response[v1.GetClaudeHistoryDetailResponse], error)
	// GetClaudeHistoryMessages retrieves messages from a specific conversation.
	GetClaudeHistoryMessages(context.Context, *connect.Request[v1.GetClaudeHistoryMessagesRequest]) (*connect.Response[v1.GetClaudeHistoryMessagesResponse], error)
	// SearchClaudeHistory performs full-text search across Claude conversation history.
	// Returns ranked results with contextual snippets showing where query terms appear.
	SearchClaudeHistory(context.Context, *connect.Request[v1.SearchClaudeHistoryRequest]) (*connect.Response[v1.SearchClaudeHistoryResponse], error)
	// PR Info and management RPCs
	GetPRInfo(context.Context, *connect.Request[v1.GetPRInfoRequest]) (*connect.Response[v1.GetPRInfoResponse], error)
	GetPRComments(context.Context, *connect.Request[v1.GetPRCommentsRequest]) (*connect.Response[v1.GetPRCommentsResponse], error)
	PostPRComment(context.Context, *connect.Request[v1.PostPRCommentRequest]) (*connect.Response[v1.PostPRCommentResponse], error)
	MergePR(context.Context, *connect.Request[v1.MergePRRequest]) (*connect.Response[v1.MergePRResponse], error)
	ClosePR(context.Context, *connect.Request[v1.ClosePRRequest]) (*connect.Response[v1.ClosePRResponse], error)
	// SendNotification allows tmux sessions to send notifications to the server.
	// Notifications are broadcast to all connected clients (web UI and TUI).
	// Requires session_id to identify the source session.
	// Enforces localhost-only restriction and rate limiting (10/sec per session).
	SendNotification(context.Context, *connect.Request[v1.SendNotificationRequest]) (*connect.Response[v1.SendNotificationResponse], error)
	// FocusWindow activates a window for the specified application.
	// Used for deep linking from notifications to bring the source IDE/terminal to front.
	// Only works on macOS via AppleScript. Requires localhost origin.
	FocusWindow(context.Context, *connect.Request[v1.FocusWindowRequest]) (*connect.Response[v1.FocusWindowResponse], error)
	// RenameSession changes the title of an existing session.
	// Validates that the new title doesn't conflict with existing sessions.
	RenameSession(context.Context, *connect.Request[v1.RenameSessionRequest]) (*connect.Response[v1.RenameSessionResponse], error)
	// RestartSession restarts a session by killing and recreating the tmux session.
	// Optionally preserves terminal output for debugging purposes.
	RestartSession(context.Context, *connect.Request[v1.RestartSessionRequest]) (*connect.Response[v1.RestartSessionResponse], error)
	// GetWorkspaceInfo retrieves VCS and workspace information for a session.
	// Returns VCS type (Git/JJ), current branch, revision, and uncommitted changes status.
	GetWorkspaceInfo(context.Context, *connect.Request[v1.GetWorkspaceInfoRequest]) (*connect.Response[v1.GetWorkspaceInfoResponse], error)
	// ListWorkspaceTargets returns available switch targets for a session.
	// Includes bookmarks/branches, recent revisions, and worktrees.
	ListWorkspaceTargets(context.Context, *connect.Request[v1.ListWorkspaceTargetsRequest]) (*connect.Response[v1.ListWorkspaceTargetsResponse], error)
	// SwitchWorkspace switches a session's workspace to a different branch, revision, or worktree.
	// The session is restarted with Claude --resume to preserve conversation context.
	SwitchWorkspace(context.Context, *connect.Request[v1.SwitchWorkspaceRequest]) (*connect.Response[v1.SwitchWorkspaceResponse], error)
	// ResolveApproval allows the web UI to approve or deny a pending Claude Code tool use request.
	// This unblocks the HTTP hook handler that is waiting for the user's decision.
	ResolveApproval(context.Context, *connect.Request[v1.ResolveApprovalRequest]) (*connect.Response[v1.ResolveApprovalResponse], error)
	// ListPendingApprovals returns all pending Claude Code tool approval requests.
	// Used by the web UI to populate the approval panel on initial load.
	ListPendingApprovals(context.Context, *connect.Request[v1.ListPendingApprovalsRequest]) (*connect.Response[v1.ListPendingApprovalsResponse], error)
	// CreateDebugSnapshot captures diagnostic information and writes it to a JSON file.
	// Gathers session state, tmux info, pending approvals, and recent logs.
	// The file is written to ~/.claude-squad/logs/debug-snapshot-{timestamp}.json.
	CreateDebugSnapshot(context.Context, *connect.Request[v1.CreateDebugSnapshotRequest]) (*connect.Response[v1.CreateDebugSnapshotResponse], error)
	// GetNotificationHistory returns persisted notification history with optional filtering.
	// Notifications survive server restarts and page refreshes.
	GetNotificationHistory(context.Context, *connect.Request[v1.GetNotificationHistoryRequest]) (*connect.Response[v1.GetNotificationHistoryResponse], error)
	// MarkNotificationRead marks specific notifications as read.
	// If notification_ids is empty, marks all notifications as read.
	MarkNotificationRead(context.Context, *connect.Request[v1.MarkNotificationReadRequest]) (*connect.Response[v1.MarkNotificationReadResponse], error)
	// ClearNotificationHistory removes notifications from the history.
	// Optionally filters by timestamp to only clear older notifications.
	ClearNotificationHistory(context.Context, *connect.Request[v1.ClearNotificationHistoryRequest]) (*connect.Response[v1.ClearNotificationHistoryResponse], error)
	// ListApprovalRules returns all auto-approval rules (user, seed, and claude-settings).
	ListApprovalRules(context.Context, *connect.Request[v1.ListApprovalRulesRequest]) (*connect.Response[v1.ListApprovalRulesResponse], error)
	// UpsertApprovalRule creates or updates a user-defined auto-approval rule.
	UpsertApprovalRule(context.Context, *connect.Request[v1.UpsertApprovalRuleRequest]) (*connect.Response[v1.UpsertApprovalRuleResponse], error)
	// DeleteApprovalRule removes a user-defined auto-approval rule by ID.
	DeleteApprovalRule(context.Context, *connect.Request[v1.DeleteApprovalRuleRequest]) (*connect.Response[v1.DeleteApprovalRuleResponse], error)
	// GetApprovalAnalytics returns aggregated analytics for classification decisions.
	GetApprovalAnalytics(context.Context, *connect.Request[v1.GetApprovalAnalyticsRequest]) (*connect.Response[v1.GetApprovalAnalyticsResponse], error)
	// ListDatabases returns all discovered workspace databases with metadata.
	// Used by the workspace switcher UI to show available workspaces.
	ListDatabases(context.Context, *connect.Request[v1.ListDatabasesRequest]) (*connect.Response[v1.ListDatabasesResponse], error)
	// GetCurrentDatabase returns metadata for the currently active workspace database.
	GetCurrentDatabase(context.Context, *connect.Request[v1.GetCurrentDatabaseRequest]) (*connect.Response[v1.GetCurrentDatabaseResponse], error)
	// SwitchDatabase switches to a different workspace database and restarts the server.
	// The server will exec-restart itself after writing a preference file.
	// The client should poll until the server is back up, then reload.
	SwitchDatabase(context.Context, *connect.Request[v1.SwitchDatabaseRequest]) (*connect.Response[v1.SwitchDatabaseResponse], error)
	// MergeDatabase copies all sessions from a source workspace database into the
	// currently active database. Skips sessions whose titles already exist.
	// No server restart required — changes are immediately visible.
	MergeDatabase(context.Context, *connect.Request[v1.MergeDatabaseRequest]) (*connect.Response[v1.MergeDatabaseResponse], error)
	// CreateCheckpoint captures the current state of a session as a named bookmark.
	// Records scrollback position, git HEAD SHA, and conversation UUID.
	CreateCheckpoint(context.Context, *connect.Request[v1.CreateCheckpointRequest]) (*connect.Response[v1.CreateCheckpointResponse], error)
	// ListCheckpoints returns all checkpoints for the specified session.
	ListCheckpoints(context.Context, *connect.Request[v1.ListCheckpointsRequest]) (*connect.Response[v1.ListCheckpointsResponse], error)
	// ForkSession creates a new independent session branched from a checkpoint.
	// The fork receives truncated scrollback, conversation history, and a git worktree
	// based on the checkpoint's recorded state.
	ForkSession(context.Context, *connect.Request[v1.ForkSessionRequest]) (*connect.Response[v1.ForkSessionResponse], error)
	// ListFiles returns the immediate children of a directory in a session's worktree.
	// Directories are returned first, then files, both alphabetically sorted.
	// Gitignored entries are excluded unless include_ignored is true.
	ListFiles(context.Context, *connect.Request[v1.ListFilesRequest]) (*connect.Response[v1.ListFilesResponse], error)
	// GetFileContent retrieves the text content of a file in a session's worktree.
	// Binary files return is_binary=true with empty content.
	// Files over 10MB are rejected; files over 1MB are served truncated with is_truncated=true.
	GetFileContent(context.Context, *connect.Request[v1.GetFileContentRequest]) (*connect.Response[v1.GetFileContentResponse], error)
	// SearchFiles performs a recursive name-substring search in a session's worktree.
	// Returns matching files with full relative paths for frontend tree reconstruction.
	// Results are capped at max_results (default 500). Minimum query length is 2 characters.
	SearchFiles(context.Context, *connect.Request[v1.SearchFilesRequest]) (*connect.Response[v1.SearchFilesResponse], error)
	// ListPathCompletions returns filesystem directory entries matching a path prefix.
	// Used by the Omnibar for real-time path completion and inline path validation.
	ListPathCompletions(context.Context, *connect.Request[v1.ListPathCompletionsRequest]) (*connect.Response[v1.ListPathCompletionsResponse], error)
	// GetSessionDefaults returns the full session defaults configuration (global, profiles, directory rules).
	GetSessionDefaults(context.Context, *connect.Request[v1.GetSessionDefaultsRequest]) (*connect.Response[v1.GetSessionDefaultsResponse], error)
	// ResolveDefaults merges all default layers for a given working directory and optional profile.
	// Returns the resolved values plus source metadata for per-field badges in the UI.
	ResolveDefaults(context.Context, *connect.Request[v1.ResolveDefaultsRequest]) (*connect.Response[v1.ResolveDefaultsResponse], error)
	// UpdateGlobalDefaults replaces the global default fields.
	UpdateGlobalDefaults(context.Context, *connect.Request[v1.UpdateGlobalDefaultsRequest]) (*connect.Response[v1.UpdateGlobalDefaultsResponse], error)
	// UpsertProfile creates or updates a named profile.
	UpsertProfile(context.Context, *connect.Request[v1.UpsertProfileRequest]) (*connect.Response[v1.UpsertProfileResponse], error)
	// DeleteProfile removes a named profile by name.
	DeleteProfile(context.Context, *connect.Request[v1.DeleteProfileRequest]) (*connect.Response[v1.DeleteProfileResponse], error)
	// UpsertDirectoryRule creates or updates a directory rule (matched by path).
	UpsertDirectoryRule(context.Context, *connect.Request[v1.UpsertDirectoryRuleRequest]) (*connect.Response[v1.UpsertDirectoryRuleResponse], error)
	// DeleteDirectoryRule removes a directory rule by path.
	DeleteDirectoryRule(context.Context, *connect.Request[v1.DeleteDirectoryRuleRequest]) (*connect.Response[v1.DeleteDirectoryRuleResponse], error)
	// ListWorktrees returns the git worktrees for a given repository path.
	// Used by the Omnibar to populate the "Use Existing Worktree" dropdown.
	ListWorktrees(context.Context, *connect.Request[v1.ListWorktreesRequest]) (*connect.Response[v1.ListWorktreesResponse], error)
	// Prompt history RPCs (S1)
	ListPromptHistory(context.Context, *connect.Request[v1.ListPromptHistoryRequest]) (*connect.Response[v1.ListPromptHistoryResponse], error)
	DeletePromptHistory(context.Context, *connect.Request[v1.DeletePromptHistoryRequest]) (*connect.Response[v1.DeletePromptHistoryResponse], error)
	// Batch session creation (S2)
	BatchCreateSessions(context.Context, *connect.Request[v1.BatchCreateSessionsRequest]) (*connect.Response[v1.BatchCreateSessionsResponse], error)
	// One-shot PR creation (S3)
	RunOneShot(context.Context, *connect.Request[v1.RunOneShotRequest]) (*connect.Response[v1.RunOneShotResponse], error)
	// Project CRUD (S4)
	CreateProject(context.Context, *connect.Request[v1.CreateProjectRequest]) (*connect.Response[v1.CreateProjectResponse], error)
	ListProjects(context.Context, *connect.Request[v1.ListProjectsRequest]) (*connect.Response[v1.ListProjectsResponse], error)
	UpdateProject(context.Context, *connect.Request[v1.UpdateProjectRequest]) (*connect.Response[v1.UpdateProjectResponse], error)
	DeleteProject(context.Context, *connect.Request[v1.DeleteProjectRequest]) (*connect.Response[v1.DeleteProjectResponse], error)
	AssignSessionsToProject(context.Context, *connect.Request[v1.AssignSessionsToProjectRequest]) (*connect.Response[v1.AssignSessionsToProjectResponse], error)
	// ListBranches returns the git branches for a given repository path.
	// Used by the SessionWizard branch autocomplete field.
	ListBranches(context.Context, *connect.Request[v1.ListBranchesRequest]) (*connect.Response[v1.ListBranchesResponse], error)
	// GetTerminalSnapshot returns the last N lines of terminal output for a session
	// without requiring an active stream. Suitable for session card previews.
	GetTerminalSnapshot(context.Context, *connect.Request[v1.GetTerminalSnapshotRequest]) (*connect.Response[v1.GetTerminalSnapshotResponse], error)
	// LogClientEvents receives batched browser console log entries from the web UI.
	// Used for remote debugging of mobile browser sessions where DevTools are unavailable.
	// Always returns an empty response; malformed entries are silently discarded.
	LogClientEvents(context.Context, *connect.Request[v1.LogClientEventsRequest]) (*connect.Response[v1.LogClientEventsResponse], error)
}

